CustomField.formula:
TRIM(
    /* ALWAYS INCLUDE THIS TAG */
    "All Interest, " &

    /* Part 1: Giving Circle Categories */
    IF(INCLUDES(npsp__Primary_Contact__r.Giving_Circle_Categories__c, "Volunteer"), "Volunteer ", "") &

    IF(OR(
        INCLUDES(npsp__Primary_Contact__r.Giving_Circle_Categories__c, "Donor"), 
        INCLUDES(npsp__Primary_Contact__r.Giving_Circle_Categories__c, "In-Kind Supporter")
    ), "Giving Circle ", "") &

    IF(INCLUDES(npsp__Primary_Contact__r.Giving_Circle_Categories__c, "Sponsor"), "Sponsor Universe ", "") &

    /* Part 2: Opportunity Record Types (By ID) */
    /* Note: 'All Interest' moved to the top, so we only check for 'Events' here */
    IF(OR(RecordTypeId = "0125e000000VbJN", RecordTypeId = "0125e000000VbJO", RecordTypeId = "012VW000001bGzi"), "Events ", "") &

    IF(RecordTypeId = "012VW000001bITd", "Events ", "") &

    IF(RecordTypeId = "0125e000001tMqa", "Professional Development ", "") &

    IF(OR(RecordTypeId = "0125e000001tMe5", RecordTypeId = "012VW000003InlJ"), "Sponsor Universe ", "")
)
